def get_detail(check_id: str) -> Optional[Dict[str, object]]:
    """Return the detailed write-up for a check id, or None if none is catalogued."""
    return FINDING_DETAIL.get(check_id)


def steps_for(check_id: str) -> List[str]:
    d = FINDING_DETAIL.get(check_id)
    return list(d.get("steps", [])) if d else []
